package main

import (
	"context"
	"fmt"
	"log"
	"net/http"
	"os"

	"github.com/go-chi/chi/v5"
	"github.com/go-chi/chi/v5/middleware"
	"github.com/jackc/pgx/v5/pgxpool"
	"github.com/kaanchinar/url-shortener/repo"
)

func main() {

	dbpool, err := pgxpool.New(context.Background(), os.Getenv("DATABASE_URL"))
	if err != nil {
		log.Fatal(err)
	}
	defer dbpool.Close()

	_ = repo.NewURLRepository(dbpool)
	r := chi.NewRouter()
	r.Use(middleware.Logger)

	r.Route("/", func(r chi.Router) {
		r.Get("/ping", func(w http.ResponseWriter, r *http.Request) {
			_, err := w.Write([]byte("pong"))
			if err != nil {
				return
			}
		})
	})

	fmt.Println("Server running on http://localhost:3000")
	err = http.ListenAndServe(":3000", r)
	if err != nil {
		return
	}
}

package main

import (
	"context"
	"fmt"
	"log"
	"net/http"
	"os"

	"github.com/go-chi/chi/v5"
	"github.com/go-chi/chi/v5/middleware"
	"github.com/jackc/pgx/v5/pgxpool"
	"github.com/kaanchinar/url-shortener/handler"
	"github.com/kaanchinar/url-shortener/repo"
	"github.com/kaanchinar/url-shortener/service"
)

func main() {

	dbpool, err := pgxpool.New(context.Background(), os.Getenv("DATABASE_URL"))
	if err != nil {
		log.Fatal(err)
	}
	defer dbpool.Close()

	urlRepo := repo.NewURLRepository(dbpool)
	urlService := service.NewURLService(urlRepo)
	urlHandler := handler.NewURLHandler(urlService)

	r := chi.NewRouter()
	r.Use(middleware.Logger)

	r.Route("/", func(r chi.Router) {
		r.Get("/ping", func(w http.ResponseWriter, r *http.Request) {
			_, err := w.Write([]byte("pong"))
			if err != nil {
				return
			}
		})
		r.Post("/shorten", urlHandler.ShortenURL)
	})

	fmt.Println("Server running on http://localhost:3000")
	err = http.ListenAndServe(":3000", r)
	if err != nil {
		return
	}
}

package handler

import (
	"encoding/json"
	"net/http"

	"github.com/kaanchinar/url-shortener/dto"
	"github.com/kaanchinar/url-shortener/service"
)

type URLHandler struct {
	svc *service.URLService
}

func NewURLHandler(s *service.URLService) *URLHandler {
	return &URLHandler{svc: s}
}

func (h *URLHandler) ShortenURL(w http.ResponseWriter, r *http.Request) {
	var req dto.CreateShortURLRequest

	err := json.NewDecoder(r.Body).Decode(&req)
	if err != nil {
		http.Error(w, "Failed to shorten URL", http.StatusBadRequest)
		return
	}

	shortID, err := h.svc.ShortenUrl(r.Context(), req)
	if err != nil {
		http.Error(w, "Failed to shorten URL", http.StatusBadRequest)
		return
	}
	res := dto.CreateShortURLResponse{
		ID:       shortID,
		ShortURL: shortID,
	}

	w.Header().Set("Content-Type", "application/json")
	err = json.NewEncoder(w).Encode(res)
	if err != nil {
		return
	}
}

package handler

import (
	"encoding/json"
	"fmt"
	"net/http"

	"github.com/kaanchinar/url-shortener/dto"
	"github.com/kaanchinar/url-shortener/service"
)

type URLHandler struct {
	svc *service.URLService
}

func NewURLHandler(s *service.URLService) *URLHandler {
	return &URLHandler{svc: s}
}

func (h *URLHandler) ShortenURL(w http.ResponseWriter, r *http.Request) {
	var req dto.CreateShortURLRequest

	err := json.NewDecoder(r.Body).Decode(&req)
	if err != nil {
		http.Error(w, "Failed to shorten URL", http.StatusBadRequest)
		return
	}

	shortID, err := h.svc.ShortenUrl(r.Context(), req)
	if err != nil {
		http.Error(w, "Failed to shorten URL", http.StatusBadRequest)
		return
	}

	fullShortURL := fmt.Sprintf("http://localhost:3000/%s", shortID)

	res := dto.CreateShortURLResponse{
		ID:       shortID,
		ShortURL: fullShortURL,
	}

	w.Header().Set("Content-Type", "application/json")
	err = json.NewEncoder(w).Encode(res)
	if err != nil {
		return
	}
}

package service

import (
	"context"
	"math/rand"
	"time"

	"github.com/kaanchinar/url-shortener/dto"
	"github.com/kaanchinar/url-shortener/model"
)

type URLRepository interface {
	CreateUrl(ctx context.Context, url model.URL) error
	GetUrlById(ctx context.Context, id string) (*model.URL, error)
}

type URLService struct {
	repo URLRepository
}

func NewURLService(repo URLRepository) *URLService {
	return &URLService{repo: repo}
}

func (s *URLService) ShortenUrl(ctx context.Context, req dto.CreateShortURLRequest) (string, error) {
	url := model.URL{
		ID:          generateUniqueID(), // Implement this function to generate a unique ID
		CreatedAt:   time.Now(),
		UpdatedAt:   time.Now(),
		OriginalURL: req.URL,
	}

	err := s.repo.CreateUrl(ctx, url)
	if err != nil {
		return "there was an error on shorten url", err
	}

	return url.ID, nil
}

func generateUniqueID() string {
	const chars = "ABCDEFGHIJKLMNOPRQSTUWXYZabcdefghijklmnoprqstuwxyz0123456789"
	const length = 7
	rng := rand.New(rand.NewSource(time.Now().UnixNano()))
	out := make([]byte, length)
	for i := 0; i < length; i++ {
		out[i] = chars[rng.Intn(len(chars))]
	}

	return string(out)
}

